import React from "react";
import { Polyline } from "react-leaflet";

function normalizeLongitude(longitude) {
  let value = longitude;

  while (value > 180) {
    value -= 360;
  }
  while (value < -180) {
    value += 360;
  }

  return value;
}

function buildFuturePath(history, samples = 28, stepMs = 20000) {
  if (history.length < 2) {
    return [];
  }

  const previous = history[history.length - 2];
  const current = history[history.length - 1];
  const deltaMs = Math.max(current.timestamp - previous.timestamp, 1000);
  const latPerMs = (current.latitude - previous.latitude) / deltaMs;
  let lonDelta = current.longitude - previous.longitude;

  if (lonDelta > 180) {
    lonDelta -= 360;
  }
  if (lonDelta < -180) {
    lonDelta += 360;
  }

  const lonPerMs = lonDelta / deltaMs;
  const projected = [];

  for (let index = 1; index <= samples; index += 1) {
    const nextLatitude = Math.max(
      -85,
      Math.min(85, current.latitude + latPerMs * stepMs * index)
    );
    const nextLongitude = normalizeLongitude(current.longitude + lonPerMs * stepMs * index);
    projected.push([nextLatitude, nextLongitude]);
  }

  return projected;
}

export default function OrbitPath({ history }) {
  const pastPath = history.map((point) => [point.latitude, point.longitude]);
  const futurePath = buildFuturePath(history);

  return (
    <>
      {pastPath.length > 1 ? (
        <>
          <Polyline
            positions={pastPath}
            pathOptions={{
              color: "#22d3ee",
              weight: 8,
              opacity: 0.16,
            }}
          />
          <Polyline
            positions={pastPath}
            pathOptions={{
              color: "#38bdf8",
              weight: 2,
              opacity: 0.9,
              dashArray: "3 8",
            }}
          />
        </>
      ) : null}
      {futurePath.length > 1 ? (
        <Polyline
          positions={futurePath}
          pathOptions={{
            color: "#7dd3fc",
            weight: 2,
            opacity: 0.7,
            dashArray: "2 10",
          }}
        />
      ) : null}
    </>
  );
}
